import React, { useState } from 'react';

function Bio({ bio }) {
  const [sanitizedBio, setSanitizedBio] = useState('');

  function sanitize(bio) {
    return bio.replace(/<[^>]*>/g, ''); // Remove all HTML tags
  }

  useEffect(() => {
    const sanitizedBio = sanitize(bio);
    setSanitizedBio(sanitizedBio);
  }, [bio]);

  return (
    <div dangerouslySetInnerHTML={{ __html: sanitizedBio }} />
  );
}